  test("public and agent-readable source-data avoids placeholder and private-note phrasing", async ({ request }) => {
    const internalSourceDataTerms =
      /\bFor Mark\b|For-Mark|Mark attention|Mark-attention|admin placeholders|For Mark placeholders|Commerce implementation notes|notes for Mark|Mark asked|Future agent|promptFromMark|Codex is working|\b[Ss]caffold\b|\b[Ss]caffolds\b|\b[Bb]oilerplate\b/;
    const publicTrustDetailTerms =
      /m@rkmoriarty\.com|mark@awesound\.com|markmoriarty@stripe\.com|codex_outbound_messages|codex_inbound_messages|raw inbound MIME|raw MIME|bumpgrade-mail|sender-authentication|smtp\.mailfrom|header\.from|allowlisted-and-authenticated|allowlisted and authenticated|trusted reply addresses|trusted sender identities/i;
    const publicSourceDataRoutes = [
      "/llms.txt",
      "/features",
      "/features/source-data",
      "/roadmap",
      "/roadmap/source-data",
      "/pricing",
      "/pricing-v2",
      "/content/source-data",
      "/pricing/source-data",
      importerSourceDataRoute,
      anonymousPlaygroundSourceDataRoute,
      "/agent-docs/source-data",
      "/agent-docs/bumpgrade-admin-surfaces",
      "/agent-docs/bumpgrade-agent-surface",
      "/agent-docs/bumpgrade-mobile-admin",
      "/mobile-admin/source-data",
      "/mobile-admin/ios/source-data",
      "/mobile-admin/android/source-data",
      "/mobile-admin/dashboard/source-data",
      "/admin/source-data",
      "/admin/director/source-data",
      "/admin/work-log/source-data",
      "/admin/user-journeys/source-data",
      "/admin/for-mark/source-data",
    ];

    for (const path of publicSourceDataRoutes) {
      const response = await request.get(path);
      const body = await response.text();
      expect(response.ok(), body).toBeTruthy();
      const contentType = response.headers()["content-type"] ?? "";
      const payload = contentType.includes("application/json") ? JSON.parse(body) : null;
      const payloadText = payload ? JSON.stringify(payload) : body;
      const copyText = payload ? publicCopyTextValues(payload).join("\n") : body;
      expect(payloadText, `${path} still exposes promptFromMark`).not.toContain("promptFromMark");
      if (path === "/agent-docs/source-data") {
        expect(payloadText, `${path} leaked project-starter implementation labels`).not.toMatch(
          /\b[Ss]caffold(?:ed|s|ing)?\b|\b[Bb]oilerplate\b/,
        );
      }
      const match = copyText.match(internalSourceDataTerms);
      expect(match, `${path} leaked "${match?.[0] ?? ""}"`).toBeNull();
      const trustDetailMatch = payloadText.match(publicTrustDetailTerms);
      expect(trustDetailMatch, `${path} leaked public trust detail "${trustDetailMatch?.[0] ?? ""}"`).toBeNull();
    }

    for (const path of ["/llms.txt", "/pricing", "/pricing-v2", "/features/source-data", "/roadmap/source-data"]) {
      const response = await request.get(path);
      const body = await response.text();
      expect(response.ok(), body).toBeTruthy();
      expect(body, `${path} leaked the internal project mailbox`).not.toContain("codex@bumpgrade.com");
      expect(body, `${path} leaked internal project-operations copy`).not.toMatch(
        /Codex project email|shipped notices|trusted replies|future Codex|notes for Mark/i,
      );
    }
  });

